    ctx.fillStyle = '#fff';
    ctx.font = `bold ${Math.floor(w * 0.022)}px sans-serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    name.split('\n').forEach((line, li) => ctx.fillText(line, w * x, h * y + (li - 0.5) * 11));
